  const [activeHabitFill, setActiveHabitFill] = useState(null); // Currently filling habit ID
  const lastClickTime = useRef({}); // Track last click time per habit
  
  // Decay timer for rapid-click mechanic
  useEffect(() => {
    if (activeHabitFill === null) return;
    
    const decayInterval = setInterval(() => {
      const now = Date.now();
      const lastClick = lastClickTime.current[activeHabitFill] || 0;
      const timeSinceClick = now - lastClick;
      
      // Grace period: don't decay for 150ms after a click
      if (timeSinceClick < 150) return;
      
      setHabitFillProgress(prev => {
        const currentFill = prev[activeHabitFill] || 0;
        if (currentFill <= 0) {
          setActiveHabitFill(null);
          return { ...prev, [activeHabitFill]: 0 };
        }
        // Decay by 6% every 80ms after grace period
        const newFill = Math.max(0, currentFill - 6);
        if (newFill <= 0) {
          setActiveHabitFill(null);
        }
        return { ...prev, [activeHabitFill]: newFill };
      });
    }, 80);
    
    return () => clearInterval(decayInterval);
  }, [activeHabitFill]);
  
